// // This module compares two 4-bit numbers and sets eq to 1 if A is less than or equal to B, and gt to 1 if A is greater than B.
module magnitude_comparison (
  input [3:0] A,
  input [3:0] B,
  output reg eq,
  output reg gt
);

  always @(*) begin
    eq = (A == B);
    gt = (A > B);
  end

endmodule
